141: // MetadataFromHeaders converts a list of header strings (each string in
142: // "Header-Name: Header-Value" form) into metadata. If a string has a header
143: // name without a value (e.g. does not contain a colon), the value is assumed
144: // to be blank. Binary headers (those whose names end in "-bin") should be
145: // base64-encoded. But if they cannot be base64-decoded, they will be assumed to
146: // be in raw form and used as is.
147: func MetadataFromHeaders(headers []string) metadata.MD {
148: 	md := make(metadata.MD)
149: 	for _, part := range headers {
150: 		if part != "" {
151: 			pieces := strings.SplitN(part, ":", 2)
152: 			if len(pieces) == 1 {
153: 				pieces = append(pieces, "") // if no value was specified, just make it "" (maybe the header value doesn't matter)
154: 			}
155: 			headerName := strings.ToLower(strings.TrimSpace(pieces[0]))
156: 			val := strings.TrimSpace(pieces[1])
157: 			if strings.HasSuffix(headerName, "-bin") {
158: 				if v, err := decode(val); err == nil {
159: 					val = v
160: 				}
161: 			}
162: 			md[headerName] = append(md[headerName], val)
163: 		}
164: 	}
165: 	return md
166: }
