170: // ExpandHeaders expands environment variables contained in the header string.
171: // If no corresponding environment variable is found an error is returned.
172: // TODO: Add escaping for `${`
173: func ExpandHeaders(headers []string) ([]string, error) {
174: 	expandedHeaders := make([]string, len(headers))
175: 	for idx, header := range headers {
176: 		if header == "" {
177: 			continue
178: 		}
179: 		results := envVarRegex.FindAllString(header, -1)
180: 		if len(results) == 0 {
181: 			expandedHeaders[idx] = headers[idx]
182: 			continue
183: 		}
184: 		expandedHeader := header
185: 		for _, result := range results {
186: 			envVarName := result[2 : len(result)-1] // strip leading `${` and trailing `}`
187: 			envVarValue, ok := os.LookupEnv(envVarName)
188: 			if !ok {
189: 				return nil, fmt.Errorf("header %q refers to missing environment variable %q", header, envVarName)
190: 			}
191: 			expandedHeader = strings.Replace(expandedHeader, result, envVarValue, -1)
192: 		}
193: 		expandedHeaders[idx] = expandedHeader
194: 	}
195: 	return expandedHeaders, nil
196: }
